2	//
3	// Tests spawn the CLI as a child process (`npx tsx src/cli.ts`), piping a
4	// scenario JSON document to stdin and capturing stdout/stderr/exit code.
5	// Expected outputs are computed via the core `processScenario` import rather
6	// than hardcoded constants, so the tests verify wiring, not arithmetic.
7	import { describe, it, expect } from "vitest";
8	import { spawnSync } from "node:child_process";
9	import { processScenario } from "./claim-office.js";
10	
11	const runCli = (scenario: unknown) =>
12	  spawnSync("npx", ["tsx", "src/cli.ts"], {
13	    input: JSON.stringify(scenario),
14	    encoding: "utf8",
15	  });
16	
17	describe("Claim Office CLI", () => {
18	  it("should write {\"results\": [...]} with the premium to stdout and exit 0 for a quote scenario on stdin", () => {
19	    const scenario = {
20	      customer: { yearsWithMHPCO: 0 },
21	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
22	    };
23	
24	    const result = runCli(scenario);
25	
26	    expect(result.status).toBe(0);
27	    expect(JSON.parse(result.stdout)).toEqual(processScenario(scenario));
28	  });
29	  it("should write results matching processScenario output (premium, then payout and remainingCap) and exit 0 for a quote+claim scenario", () => {
30	    const scenario = {
